3_real_world_example.code:
function second() {
  console.log('Second running');
  // Throwing an error here shows first() and second() in the Stack trace!
}

function first() {
  second();
}

first();

6_edge_case.code:
function recurse() {
  recurse(); // Infinite recursive loop
}
try {
  recurse();
} catch (err) {
  console.log(err.message); // RangeError: Maximum call stack size exceeded
}
